#include <iostream>
using namespace std;

int main() {
    int marks;
    cout << "Enter marks (0-100): ";
    cin >> marks;

    if (marks < 0 || marks > 100) {
        cout << "Invalid marks" << endl;
    } else if (marks >= 90) {
        cout << "Grade: A" << endl;
    } else if (marks >= 80) {
        cout << "Grade: B" << endl;
    } else if (marks >= 70) {
        cout << "Grade: C" << endl;
    } else if (marks >= 60) {
        cout << "Grade: D" << endl;
    } else {
        cout << "Grade: F" << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a, b, c;
    cout << "Enter three numbers: ";
    cin >> a >> b >> c;

    int largest;
    if (a >= b) {
        if (a >= c) {
            largest = a;
        } else {
            largest = c;
        }
    } else {
        if (b >= c) {
            largest = b;
        } else {
            largest = c;
        }
    }

    cout << "Largest: " << largest << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int x = -7;
    int absX = (x >= 0) ? x : -x;
    cout << "Absolute value of " << x << ": " << absX << endl;

    int a = 25, b = 18;
    int minVal = (a < b) ? a : b;
    int maxVal = (a > b) ? a : b;
    cout << "Min: " << minVal << ", Max: " << maxVal << endl;

    // Nested ternary: classify number
    int num = 0;
    string result = (num > 0) ? "positive" : (num < 0) ? "negative" : "zero";
    cout << num << " is " << result << endl;

    return 0;
}

