    int minAB = (a < b) ? a : b;
    int minCD = (c < d) ? c : d;
    int minVal = (minAB < minCD) ? minAB : minCD;
    int maxAB = (a > b) ? a : b;
    int maxCD = (c > d) ? c : d;
